use std::f64::consts::PI;
use crate::types::{DecideInput, DecideOutput};

const SIX_SIG_FACTOR: f64 = 0.5e-6; // tolerance for six significant digits

fn realcompare(a: f64, b: f64) -> &'static str {
    let max_ab = a.abs().max(b.abs());
    if max_ab == 0.0 {
        return "EQ";
    }
    let tol = SIX_SIG_FACTOR * max_ab;
    let diff = (a - b).abs();
    if diff <= tol {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()) / 2.0
}

fn angle_three_points(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    let v1x = x1 - x2;
    let v1y = y1 - y2;
    let v2x = x3 - x2;
    let v2y = y3 - y2;
    let l1 = (v1x * v1x + v1y * v1y).sqrt();
    let l2 = (v2x * v2x + v2y * v2y).sqrt();
    if realcompare(l1, 0.0) == "EQ" || realcompare(l2, 0.0) == "EQ" {
        return None;
    }
    let dot = v1x * v2x + v1y * v2y;
    let cos_theta = (dot / (l1 * l2)).clamp(-1.0, 1.0);
    Some(cos_theta.acos())
}

fn minimal_circle_radius(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    x3: f64,
    y3: f64,
) -> f64 {
    let a = distance(x1, y1, x2, y2);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x2, y2, x3, y3);
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if realcompare(area, 0.0) == "EQ" {
        // Colinear: circle defined by the furthest two points
        a.max(b.max(c)) / 2.0
    } else {
        (a * b * c) / (4.0 * area)
    }
}

fn distance_point_to_line(px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    if realcompare(ax, bx) == "EQ" && realcompare(ay, by) == "EQ" {
        return distance(px, py, ax, ay);
    }
    let numerator = ((by - ay) * px - (bx - ax) * py + bx * ay - by * ax).abs();
    let denom = ((by - ay).powi(2) + (bx - ax).powi(2)).sqrt();
    numerator / denom
}

fn quadrant(x: f64, y: f64) -> u8 {
    if realcompare(x, 0.0) != "LT" && realcompare(y, 0.0) != "LT" {
        1
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) != "LT" {
        2
    } else if realcompare(x, 0.0) != "GT" && realcompare(y, 0.0) == "LT" {
        3
    } else {
        4
    }
}

fn lic1(input: &DecideInput) -> bool {
    let n = input.numpoints;
    for i in 0..(n - 1) {
        let d = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    for i in 0..(n - 2) {
        let r = minimal_circle_radius(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(r, input.parameters.radius1) == "GT" {
            return true;
        }
    }
    false
}

fn lic3(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let lower = PI - input.parameters.epsilon;
    let upper = PI + input.parameters.epsilon;
    for i in 0..(n - 2) {
        if let Some(ang) = angle_three_points(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        ) {
            if realcompare(ang, lower) == "LT" || realcompare(ang, upper) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic4(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    for i in 0..(n - 2) {
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads_limit = input.parameters.quads;
    if q_pts < 2 || q_pts > input.numpoints {
        return false;
    }
    let n = input.numpoints;
    for start in 0..=n - q_pts {
        let mut seen = [false; 4];
        for idx in start..start + q_pts {
            let q = quadrant(input.x[idx], input.y[idx]);
            seen[(q - 1) as usize] = true;
        }
        let distinct = seen.iter().filter(|v| **v).count();
        if distinct > quads_limit {
            return true;
        }
    }
    false
}

fn lic6(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 2 {
        return false;
    }
    for i in 0..(n - 1) {
        let diff = input.x[i + 1] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    let n_pts = input.parameters.n_pts;
    if input.numpoints < 3 || n_pts > input.numpoints {
        return false;
    }
    for start in 0..=input.numpoints - n_pts {
        let first_idx = start;
        let last_idx = start + n_pts - 1;
        let ax = input.x[first_idx];
        let ay = input.y[first_idx];
        let bx = input.x[last_idx];
        let by = input.y[last_idx];
        for idx in first_idx..=last_idx {
            let d = distance_point_to_line(input.x[idx], input.y[idx], ax, ay, bx, by);
            if realcompare(d, input.parameters.dist) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic8(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;
    let n = input.numpoints;
    if n < 3 || k_pts > n - 2 {
        return false;
    }
    for i in 0..=n - k_pts - 2 {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let n = input.numpoints;
    if n < 5 || a_pts + b_pts > n - 3 {
        return false;
    }
    for i in 0..=n - (a_pts + b_pts + 3) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        let r = minimal_circle_radius(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if realcompare(r, input.parameters.radius1) == "GT" {
            return true;
        }
    }
    false
}

fn lic10(input: &DecideInput) -> bool {
    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    let n = input.numpoints;
    if n < 5 || c_pts + d_pts > n - 3 {
        return false;
    }
    let lower = PI - input.parameters.epsilon;
    let upper = PI + input.parameters.epsilon;
    for i in 0..=n - (c_pts + d_pts + 3) {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;
        if let Some(ang) = angle_three_points(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        ) {
            if realcompare(ang, lower) == "LT" || realcompare(ang, upper) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic11(input: &DecideInput) -> bool {
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let n = input.numpoints;
    if n < 5 || e_pts + f_pts > n - 3 {
        return false;
    }
    for i in 0..=n - (e_pts + f_pts + 3) {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if realcompare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(input: &DecideInput) -> bool {
    let g_pts = input.parameters.g_pts;
    let n = input.numpoints;
    if n < 3 || g_pts > n - 2 {
        return false;
    }
    for i in 0..=n - g_pts - 2 {
        let j = i + g_pts + 1;
        let diff = input.x[j] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;
    let n = input.numpoints;
    if n < 3 || k_pts > n - 2 {
        return false;
    }
    let mut part1 = false; // distance > LENGTH1
    let mut part2 = false; // distance < LENGTH2
    for i in 0..=n - k_pts - 2 {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if !part1 && realcompare(d, input.parameters.length1) == "GT" {
            part1 = true;
        }
        if !part2 && realcompare(d, input.parameters.length2) == "LT" {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }
    false
}

fn lic14(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let n = input.numpoints;
    if n < 5 || a_pts + b_pts > n - 3 {
        return false;
    }
    let mut part1 = false; // cannot be contained within RADIUS1
    let mut part2 = false; // can be contained within or on RADIUS2
    for i in 0..=n - (a_pts + b_pts + 3) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        let r = minimal_circle_radius(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if !part1 && realcompare(r, input.parameters.radius1) == "GT" {
            part1 = true;
        }
        if !part2 && realcompare(r, input.parameters.radius2) != "GT" {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }
    false
}

fn lic15(input: &DecideInput) -> bool {
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let n = input.numpoints;
    if n < 5 || e_pts + f_pts > n - 3 {
        return false;
    }
    let mut part1 = false; // area > AREA1
    let mut part2 = false; // area < AREA2
    for i in 0..=n - (e_pts + f_pts + 3) {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if !part1 && realcompare(area, input.parameters.area1) == "GT" {
            part1 = true;
        }
        if !part2 && realcompare(area, input.parameters.area2) == "LT" {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }
    false
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];
    cmv[0] = lic1(input);
    cmv[1] = lic2(input);
    cmv[2] = lic3(input);
    cmv[3] = lic4(input);
    cmv[4] = lic5(input);
    cmv[5] = lic6(input);
    cmv[6] = lic7(input);
    cmv[7] = lic8(input);
    cmv[8] = lic9(input);
    cmv[9] = lic10(input);
    cmv[10] = lic11(input);
    cmv[11] = lic12(input);
    cmv[12] = lic13(input);
    cmv[13] = lic14(input);
    cmv[14] = lic15(input);

    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in (i + 1)..15 {
            let val = match input.lcm[i][j].as_str() {
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => true, // NOTUSED
            };
            pum[i][j] = val;
            pum[j][i] = val;
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if pum[i][i] == false {
            fuv[i] = true;
            continue;
        }
        let all_true = pum[i].iter().all(|v| *v);
        fuv[i] = all_true;
    }

    let launch = fuv.iter().all(|v| *v);
    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    #[test]
    fn test_realcompare_basic() {
        assert_eq!(realcompare(1.0, 1.0), "EQ");
        assert_eq!(realcompare(1.0000001, 1.0), "EQ");
        assert_eq!(realcompare(1.1, 1.0), "GT");
        assert_eq!(realcompare(0.9, 1.0), "LT");
    }
}
